+package com.google.gson.internal;
+
+import com.google.gson.TypeAdapter;
+
+/**
+ * Internal interface for adapters whose serialization is delegated to another adapter.
+ */
+public interface SerializationDelegatingTypeAdapter {
+  /**
+   * Returns the adapter that is actually used for serialization, or {@code this} if serialization
+   * is not delegated.
+   */
+  TypeAdapter<?> getSerializationDelegate();
+}
